import { readFile, writeFile } from "node:fs/promises";
import path from "node:path";
import { fileURLToPath } from "node:url";

const __dirname = path.dirname(fileURLToPath(import.meta.url));
const root = path.resolve(__dirname, "..");
const jsonPath = path.join(root, "docs", "tools-design.json");
const dataPath = path.join(root, "docs", "tools-design.data.js");

const database = await readFile(jsonPath, "utf8");
JSON.parse(database);

await writeFile(
  dataPath,
  [
    "// Generated from tools-design.json. Do not edit this file by hand.",
    "// It exists so tools-design.html can auto-load data when opened as file://.",
    `window.__BATCHIMAGER_TOOLS_DESIGN__ = ${database.trim()};`,
    ""
  ].join("\n"),
  "utf8"
);
